import { useEffect, useState } from "react";
import { reportsAPI } from "../../services/api";

export default function Reports() {
  const [summary, setSummary] = useState(null);

  useEffect(() => {
    reportsAPI.getSummary().then(res => setSummary(res.data)).catch(console.error);
  }, []);

  return (
    <main className="page">
      <section className="page-hero">
        <h1>التقارير</h1>
        <p>ملخص سريع عن التقارير والمشاكل المرورية داخل النظام.</p>
      </section>

      {summary && (
        <section className="cards-grid">
          <div className="info-card"><h3>{summary.totalRoads}</h3><p>إجمالي الطرق</p></div>
          <div className="info-card"><h3>{summary.activeReports}</h3><p>تقارير نشطة</p></div>
          <div className="info-card"><h3>{summary.resolvedReports}</h3><p>تقارير تم حلها</p></div>
          <div className="info-card"><h3>{summary.trafficAlerts}</h3><p>تنبيهات مرورية</p></div>
        </section>
      )}
    </main>
  );
}
